+    fn retained_autocommit_count_star_sum_row_in_txn(
+        &self,
+        cx: &Cx,
+        txn: &mut dyn TransactionHandle,
+        table: &TableSchema,
+        sum_column_index: usize,
+        rowid_alias_column_index: Option<usize>,
+    ) -> Result<Row> {
+        let Some(root) = PageNumber::new(u32::try_from(table.root_page).unwrap_or(0)) else {
+            return Ok(Row {
+                values: vec![SqliteValue::Integer(0), SqliteValue::Null],
+            });
+        };
+        let mut cursor = Self::new_pager_btree_cursor(cx, txn, root, true)?;
+        let mut count = 0_i64;
+        let mut int_sum: i64 = 0;
+        let mut float_sum: f64 = 0.0;
+        let mut has_float = false;
+        let mut has_any_non_null = false;
+        let mut needs_fallback = false;
+
+        if cursor.first(cx)? {
+            loop {
+                let rowid = cursor.rowid(cx)?;
+                let payload = cursor.payload(cx)?;
+                let values = self.decode_table_row_values_from_payload(
+                    table,
+                    rowid,
+                    &payload,
+                    rowid_alias_column_index,
+                )?;
+                count = count.checked_add(1).ok_or_else(|| {
+                    FrankenError::Internal(format!(
+                        "table row count exceeds i64 for root page {}",
+                        table.root_page
+                    ))
+                })?;
+                let value = memdb_row_value_with_rowid_alias(
+                    rowid,
+                    &values,
+                    sum_column_index,
+                    rowid_alias_column_index,
+                );
+                match &value {
+                    SqliteValue::Null => {}
+                    SqliteValue::Integer(n) => {
+                        has_any_non_null = true;
+                        if let Some(sum) = int_sum.checked_add(*n) {
+                            int_sum = sum;
+                        } else {
+                            #[allow(clippy::cast_precision_loss)]
+                            {
+                                float_sum += int_sum as f64 + *n as f64;
+                            }
+                            int_sum = 0;
+                            has_float = true;
+                        }
+                    }
+                    SqliteValue::Float(f) => {
+                        has_any_non_null = true;
+                        has_float = true;
+                        float_sum += f;
+                    }
+                    SqliteValue::Text(_) | SqliteValue::Blob(_) => {
+                        needs_fallback = true;
+                        break;
+                    }
+                }
+                if !cursor.next(cx)? {
+                    break;
+                }
+            }
+        }
+
+        let sum = if needs_fallback {
+            let mut sum_values: Vec<SqliteValue> = Vec::new();
+            let mut cursor = Self::new_pager_btree_cursor(cx, txn, root, true)?;
+            if cursor.first(cx)? {
+                loop {
+                    let rowid = cursor.rowid(cx)?;
+                    let payload = cursor.payload(cx)?;
+                    let values = self.decode_table_row_values_from_payload(
+                        table,
+                        rowid,
+                        &payload,
+                        rowid_alias_column_index,
+                    )?;
+                    let value = memdb_row_value_with_rowid_alias(
+                        rowid,
+                        &values,
+                        sum_column_index,
+                        rowid_alias_column_index,
+                    );
+                    if !value.is_null() {
+                        sum_values.push(value);
+                    }
+                    if !cursor.next(cx)? {
+                        break;
+                    }
+                }
+            }
+            let sum_refs = sum_values.iter().collect::<Vec<_>>();
+            self.compute_sum_aggregate_with_registry(&sum_refs)?
+        } else if !has_any_non_null {
+            SqliteValue::Null
+        } else if has_float {
+            #[allow(clippy::cast_precision_loss)]
+            SqliteValue::Float(float_sum + int_sum as f64)
+        } else {
+            SqliteValue::Integer(int_sum)
+        };
+
+        Ok(Row {
+            values: vec![SqliteValue::Integer(count), sum],
+        })
+    }
